package com.back.capstone.security;
import jakarta.servlet.*; import jakarta.servlet.http.*; import java.io.IOException; import org.springframework.security.authentication.UsernamePasswordAuthenticationToken; import org.springframework.security.core.context.SecurityContextHolder; import org.springframework.security.core.userdetails.*; import org.springframework.security.web.authentication.WebAuthenticationDetailsSource; import org.springframework.stereotype.Component; import org.springframework.web.filter.OncePerRequestFilter;
@Component public class JwtAuthenticationFilter extends OncePerRequestFilter { private final JwtService jwt;private final CustomUserDetailsService uds;public JwtAuthenticationFilter(JwtService j,CustomUserDetailsService u){jwt=j;uds=u;} protected void doFilterInternal(HttpServletRequest req,HttpServletResponse res,FilterChain chain)throws ServletException,IOException{String h=req.getHeader("Authorization");if(h!=null&&h.startsWith("Bearer ")){String t=h.substring(7);if(jwt.valid(t)&&SecurityContextHolder.getContext().getAuthentication()==null){UserDetails u=uds.loadUserByUsername(jwt.username(t));var a=new UsernamePasswordAuthenticationToken(u,null,u.getAuthorities());a.setDetails(new WebAuthenticationDetailsSource().buildDetails(req));SecurityContextHolder.getContext().setAuthentication(a);}}chain.doFilter(req,res);}}
